"use client";

import React, { useEffect, useState } from "react";
import { Tag, MapPin, Calendar, Clock, Info } from "lucide-react";

const ItemDetails = () => {
  //const { id } = params;

  const [item, setItem] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchItem = async () => {
      try {
        const token = localStorage.getItem("accessToken"); // if protected

        const res = await fetch(`http://localhost:5000/item/details/${id}`, {
          headers: {
            "Content-Type": "application/json",
            Authorization: token ? `Bearer ${token}` : "",
          },
        });

        const data = await res.json();
        setItem(data.data || data); // depends on your API structure
        setLoading(false);
      } catch (err) {
        console.error(err);
        setLoading(false);
      }
    };

    fetchItem();
  }, [id]);

  if (loading) return <div className="p-10 text-center">Loading...</div>;

  if (!item) return <div className="p-10 text-center">Item not found.</div>;

  const formatDate = (d) => new Date(d).toLocaleDateString("en-GB");

  return (
    <div className="max-w-4xl min-h-[90vh] mx-auto p-6 space-y-6">
      <h1 className="text-3xl md:text-4xl font-bold text-gray-900">
        {item.itemName}
      </h1>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Image */}
        <div className="w-full flex justify-center">
          <img
            src={
              item.photos?.[0] ||
              "https://placehold.co/500x500/4F46E5/FFFFFF?text=Item"
            }
            alt={item.itemName}
            className="rounded-xl shadow-lg border object-cover"
          />
        </div>

        {/* Details */}
        <div className="space-y-5">
          {/* Status */}
          <div
            className={`text-center py-2 rounded-xl font-bold text-lg shadow ${
              item.status === "pending"
                ? "bg-yellow-100 text-yellow-700"
                : item.status === "accepted"
                ? "bg-green-100 text-green-700"
                : "bg-red-100 text-red-700"
            }`}
          >
            STATUS: {item.status.toUpperCase()}
          </div>

          {/* Info Card */}
          <div className="bg-gray-50 p-5 rounded-xl border border-gray-200 space-y-4 shadow-sm">
            <h3 className="text-xl font-semibold flex items-center text-gray-800">
              <Info className="w-5 h-5 mr-2 text-indigo-600" />
              Item Information
            </h3>

            <p className="text-gray-600">{item.description}</p>

            <div className="space-y-3 text-sm text-gray-700">
              <p className="flex items-center">
                <Tag className="w-4 h-4 mr-2 text-indigo-500" />
                <strong className="mr-1">Category:</strong> {item.category}
              </p>

              <p className="flex items-center">
                <MapPin className="w-4 h-4 mr-2 text-indigo-500" />
                <strong className="mr-1">Location:</strong> {item.location}
              </p>

              <p className="flex items-center">
                <Calendar className="w-4 h-4 mr-2 text-indigo-500" />
                <strong className="mr-1">Date:</strong> {formatDate(item.date)}
              </p>

              <p className="flex items-center">
                <Clock className="w-4 h-4 mr-2 text-indigo-500" />
                <strong className="mr-1">Posted On:</strong>{" "}
                {formatDate(item.createdAt)}
              </p>
            </div>
          </div>

          {/* Claim Button */}
          <button
            disabled={item.status !== "pending"}
            className="
              w-full py-3 rounded-xl font-semibold text-lg shadow-md transition
              bg-indigo-600 text-white hover:bg-indigo-700
              disabled:bg-gray-400 disabled:cursor-not-allowed
            "
          >
            Claim This Item
          </button>
        </div>
      </div>
    </div>
  );
};

export default ItemDetails;
